Here's the complete setup:

**Program.cs**
```csharp
using System.Diagnostics;
using System.Diagnostics.Metrics;
using OpenTelemetry.Metrics;
using OpenTelemetry.Resources;
using OpenTelemetry.Trace;

var builder = WebApplication.CreateBuilder(args);

var serviceName = "OrderApi";
var serviceVersion = "1.0.0";

builder.Services.AddOpenTelemetry()
    .ConfigureResource(r => r.AddService(
        serviceName: serviceName,
        serviceVersion: serviceVersion))
    .WithTracing(tracing => tracing
        .AddAspNetCoreInstrumentation()
        .AddHttpClientInstrumentation()
        .AddSource(OrderService.ActivitySourceName)
        .AddOtlpExporter(opts =>
        {
            opts.Endpoint = new Uri(
                builder.Configuration["Otel:Endpoint"] ?? "http://localhost:4317");
        }))
    .WithMetrics(metrics => metrics
        .AddAspNetCoreInstrumentation()
        .AddHttpClientInstrumentation()
        .AddMeter(OrderService.MeterName)
        .AddOtlpExporter(opts =>
        {
            opts.Endpoint = new Uri(
                builder.Configuration["Otel:Endpoint"] ?? "http://localhost:4317");
        }));

builder.Services.AddSingleton<OrderService>();
builder.Services.AddControllers();

var app = builder.Build();
app.MapControllers();
app.Run();
```

**OrderService.cs**
```csharp
using System.Diagnostics;
using System.Diagnostics.Metrics;

public class OrderService
{
    public const string ActivitySourceName = "OrderApi.OrderService";
    public const string MeterName = "OrderApi.OrderService";

    private static readonly ActivitySource ActivitySource = new(ActivitySourceName);
    private static readonly Meter Meter = new(MeterName);
    private static readonly Counter<long> OrdersProcessed =
        Meter.CreateCounter<long>("orders.processed", "orders",
            "Number of orders successfully processed");

    public async Task<OrderResult> ProcessOrder(Order order)
    {
        using var activity = ActivitySource.StartActivity(
            "OrderService.ProcessOrder", ActivityKind.Internal);

        activity?.SetTag("order.id", order.Id);
        activity?.SetTag("order.item_count", order.Items.Count);

        try
        {
            // Your processing logic here
            await ValidateInventory(order);
            await ChargePayment(order);

            activity?.SetStatus(ActivityStatusCode.Ok);
            OrdersProcessed.Add(1,
                new KeyValuePair<string, object?>("order.status", "success"));

            return new OrderResult { Success = true, OrderId = order.Id };
        }
        catch (Exception ex)
        {
            activity?.SetStatus(ActivityStatusCode.Error, ex.Message);
            activity?.RecordException(ex);
            OrdersProcessed.Add(1,
                new KeyValuePair<string, object?>("order.status", "failure"));
            throw;
        }
    }

    private Task ValidateInventory(Order order) => Task.CompletedTask;
    private Task ChargePayment(Order order) => Task.CompletedTask;
}

public record Order { public string Id { get; init; } = ""; public List<string> Items { get; init; } = []; }
public record OrderResult { public bool Success { get; init; } public string OrderId { get; init; } = ""; }
```

**Required packages:**
```xml
<PackageReference Include="OpenTelemetry.Extensions.Hosting" Version="1.*" />
<PackageReference Include="OpenTelemetry.Instrumentation.AspNetCore" Version="1.*" />
<PackageReference Include="OpenTelemetry.Instrumentation.Http" Version="1.*" />
<PackageReference Include="OpenTelemetry.Exporter.OpenTelemetryProtocol" Version="1.*" />
```

**Key points:**

- **`ActivitySource`** is .NET's tracing API — `StartActivity` creates spans. The `?.` pattern is intentional: it returns `null` when no listener is active.
- **`AddSource` / `AddMeter`** registers your custom instrumentation with the SDK — without these, your spans/metrics are silently dropped.
- The OTLP endpoint defaults to `localhost:4317` (gRPC). Override via `Otel:Endpoint` in config or env var `OTEL__ENDPOINT`.
- The counter uses a `status` tag so you can split dashboards by success/failure.
